INSERT INTO public.photos VALUES (25400, 'Tв”ңв•‘mulo Baltasar Carlos 1646', 'En 1646, el rey Felipe IV y su hijo el prв”ңВЎncipe Baltasar Carlos viajaron a Zaragoza, donde el chaval, de 16 aв”ңв–’os, contrajo la viruela y muriв”ңв”Ӯ, el 9 de octubre. Su cadв”ңГӯver permaneciв”ңв”Ӯ en la ciudad hasta el 16, cuando fue trasladado a Monasterio de San Lorenzo de El Escorial. Posteriormente se le hicieron dos capillas ardientes; una en la Seo y otra en la plaza del Mercado, donde se acostumbraban a celebrar las exequias reales. Para esta в”ңв•‘ltima, la Junta eligiв”ңв”Ӯ la traza de Miguel Ramв”ңв”Ӯn. Se hicieron solemnes vв”ңВЎsperas y responsos durante los dв”ңВЎas de la vigilia y de las exequias, 20 y 21 de octubre. En el grabado, de Josephus Vallв”ңВ®s, se representa el tв”ңв•‘mulo honorв”ңВЎfico de la plaza del Mercado, que medв”ңВЎa 154 palmos de altura. Este dibujo estв”ңГӯ incluido en la publicaciв”ңв”Ӯn "Obelisco histв”ңв”Ӯrico y honorario que la imperial ciudad de Zaragoza erigiв”ңв”Ӯ a la inmortal memoria del serenв”ңВЎsimo seв”ңв–’or don Balsar Carlos de Austria, prв”ңВЎncipe de las Espaв”ңв–’as", escrito por Juan Francisco Andrв”ңВ®s, cronista del reino de Aragв”ңв”Ӯn, en Zaragoza, 1646. Fuente visual: Biblioteca Nacional de Austria.', 1646, 1646, 1646, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30842811992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30842811992.webp', 'https://www.flickr.com/photos/zaragozaantigua/30842811992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25403, 'Ocupaciв”ңв”Ӯn castellana 1591', 'Г”ГҮВЈNuevos suplicios en Zaragoza durante la ocupaciв”ңв”Ӯn por tropas castellanasГ”ГҮГҳ. Grabado del siglo XIX coloreado posteriormente. Tras las alteraciones de Zaragoza del verano de 1591, el ejв”ңВ®rcito de Castilla tomв”ңв”Ӯ Zaragoza, en noviembre. Varias personas fueron ejecutadas, previamente a la decapitaciв”ңв”Ӯn del Justicia Juan de Lanuza. Fuente visual: www.magnoliabox.com', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40390624734.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40390624734.webp', 'https://www.flickr.com/photos/zaragozaantigua/40390624734/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25816, 'Vista de Zaragoza c.1866', 'A.M.Z. Sign. 0854. Vista de Zaragoza. [1880]. Realizada circa 1866. Dibujo de Francisco Pradilla. Se observa la torre de la iglesia de San Pablo y las iglesias de San Juan de los Panetes y Santa Isabel. En el texto explicativo del Ayuntamiento de Zaragoza se asegura que en la imagen la disposiciв”ңв”Ӯn original estв”ңГӯ invertida. Nosotros aв”ңв–’adimos que segв”ңв•‘n se mire. Fechada mediante los datos aportados en www.facebook.com/photo.php?fbid=376521369171365&set=g...', 1866, 1866, 1866, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65584300, -0.88874200, '0101000020E6100000BB9C12109370ECBFBF27D6A9F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14858571632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14858571632.webp', 'https://www.flickr.com/photos/zaragozaantigua/14858571632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25819, 'Calle Miguel de Ara 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Ara, (Miguel)." Esta es una larga y estrecha calle que une la calle de San Pablo con la de Pignatelli. En la imagen, tramo de la calle Miguel de Ara desde la calle General Franco, hasta la de Basilio Boggiero, al fondo.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65464700, -0.88620500, '0101000020E61000005DA79196CA5BECBF56B60F79CBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14886572007.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14886572007.webp', 'https://www.flickr.com/photos/zaragozaantigua/14886572007/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25820, 'Calle de Boggiero 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Boggiero." Esta es una calle que nace en la calle Escuelas Pв”ңВЎas y termina en la de Santa Inв”ңВ®s. Imagen de la calle tomada desde su comienzo en Escuelas Pв”ңВЎas. A la izquierda, la Iglesia y el colegio de los Escolapios.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65482100, -0.88448500, '0101000020E610000092AE997CB34DECBFF4DDAD2CD1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14887541828.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14887541828.webp', 'https://www.flickr.com/photos/zaragozaantigua/14887541828/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25821, 'Calle de Boggiero 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Boggiero." Esta es una calle que nace en la calle Escuelas Pв”ңВЎas y termina en la de Santa Inв”ңВ®s. Imagen de la calle entre la calle de Miguel de Ara y la de Cerezo.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65537400, -0.88664100, '0101000020E6100000185E49F25C5FECBF0953944BE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14887618370.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14887618370.webp', 'https://www.flickr.com/photos/zaragozaantigua/14887618370/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25823, 'Calle del Saco 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle del Saco." Menos que calle, tratв”ңГӯbase de un callejв”ңв”Ӯn de la calle Echeandв”ңВЎa, a poco de empezarla desde la calle Boggiero.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65539000, -0.88531100, '0101000020E6100000F23FF9BB7754ECBF0E10CCD1E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14897956267.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14897956267.webp', 'https://www.flickr.com/photos/zaragozaantigua/14897956267/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25824, 'Torre de San Pablo 1874', 'J. Laurent. 1874.', 1874, 1874, 1874, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65617500, -0.88619200, '0101000020E610000035423F53AF5BECBFF5B9DA8AFDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14924757262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14924757262.webp', 'https://www.flickr.com/photos/zaragozaantigua/14924757262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25825, 'Iglesia de San Pablo 1844', 'Dibujo de Jenaro Pв”ңВ®rez Villaamil, grabado por A. Guesjoв”ңв•Ј, lith., por la casa A. Hauser, impreso por Lemercier, e incluido en la obra "Espaв”ңв–’a artв”ңВЎstica y monumental vistas y descripciв”ңв”Ӯn de los sitios y monumentos mв”ңГӯs notables de Espaв”ңв–’a", Parв”ңВЎs.', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65606400, -0.88593500, '0101000020E610000061376C5B9459ECBF9E0AB8E7F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14957554115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14957554115.webp', 'https://www.flickr.com/photos/zaragozaantigua/14957554115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25829, 'Iglesia de San Pablo 1865', 'Portada Norte de la iglesia de San Pablo hacia 1865. Portada gв”ңв”Ӯtica del siglo XV esculpida en alabastro, que da a la calle de San Blas. Llamada Puerta de la Tramontana o Puerta del Santo Cristo. En 1594 se le aв”ңв–’ade el alero de madera. Fuente: Colecciв”ңв”Ӯn Antonio Arguas.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65630000, -0.88583600, '0101000020E610000095D233BDC458ECBFB22E6EA301D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15169430412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15169430412.webp', 'https://www.flickr.com/photos/zaragozaantigua/15169430412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25831, 'San Pablo 1877', 'Imagen en relativa altura de la poderosa torre de la parroquia de San Pablo, tomada desde el oeste, lo que permite ver la antigua puerta abierta a los pies de la iglesia en 1587, llamada del Fosal porque allв”ңВЎ estaba el cementerio parroquial, y luego de los Ajusticiados, en la angulosa plaza de San Pablo. A la izquierda, al fondo, el Torreв”ңв”Ӯn de la Zuda, y la original e inacabada в”ңв•‘nica torre del Pilar. A la derecha, la Torre Nueva. A su lado, la torre de San Felipe. Fuente visual: Fototeca del Patrimonio Histв”ңв”Ӯrico, Archivo Ruiz Vernacci. Foto Jean Laurent.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20168997966.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20168997966.webp', 'https://www.flickr.com/photos/zaragozaantigua/20168997966/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25833, 'Calle San Blas 1998', 'Excavaciв”ңв”Ӯn arqueolв”ңв”Ӯgica en el cruce de la calle San Blas con Aguadores (izquierda), con motivo de las obras de alineaciв”ңв”Ӯn de la zona en octubre de 1998. Al fondo, la torre de San Pablo. Se hallaron restos de hornos de в”ңВ®poca islв”ңГӯmica y una cisterna romana. Fuente: Colecciв”ңв”Ӯn particular.', 1998, 1998, 1998, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65661600, -0.88717900, '0101000020E6100000E355D636C563ECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22020688995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22020688995.webp', 'https://www.flickr.com/photos/zaragozaantigua/22020688995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25834, 'San Pablo c.1877', '"Iglesia de San Pablo. Puerta del Cristo". Imagen de la puerta norte, o "Tramontana", de la iglesia parroquial de San Pablo, que permitв”ңВЎa el acceso al templo desde la calle de San Blas. Esta puerta estв”ңГӯ datada en el siglo XV, cuando Antв”ңв”Ӯn del Prado tallв”ңв”Ӯ en madera el frontв”ңв”Ӯn plateresco que la corona. Actualmente se halla tapiada, y despojada de los dos bancos laterales. Fuente visual: Jean Laurent y Cв”ңВЎa, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histв”ңв”Ӯrico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65632200, -0.88595300, '0101000020E6100000FA60191BBA59ECBF9AD2FA5B02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22643885050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22643885050.webp', 'https://www.flickr.com/photos/zaragozaantigua/22643885050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25835, 'Plaza de San Pablo 1951', 'Imagen de la antigua plaza de San Pablo, como espacio delimitado por los pies de la iglesia parroquial de San Pablo (derecha), con el acceso a travв”ңВ®s de la puerta de los Ahorcados, o del Fosal; la calle de San Blas (al fondo); y la propia calle de San Pablo (en primer plano). Fuente visual: Archivo Mora, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65621000, -0.88656500, '0101000020E610000058E71890BD5EECBF72A774B0FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22798168538.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22798168538.webp', 'https://www.flickr.com/photos/zaragozaantigua/22798168538/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25837, 'Calle de San Blas 1998', 'A finales de abril de 1997 el Ayuntamiento de Zaragoza aprobв”ңв”Ӯ, en Pleno Municipal Extraordinario, el primer Plan Integral del Casco Histв”ңв”Ӯrico (PICH), que con un presupuesto de casi 21.000 millones de pesetas tenв”ңВЎa previsto impulsar 18 programas y mв”ңГӯs de 200 actuaciones hasta 2004, la mayor parte a travв”ңВ®s de la Sociedad Municipal de Rehabilitaciв”ңв”Ӯn Urbana, al objeto de "romper la segregaciв”ңв”Ӯn social y espacial" de esta zona de la ciudad, sobre todo en los barrios de San Pablo, y La Magdalena. La inicial gestiв”ңв”Ӯn del PP puso acento destacado en los aspectos fв”ңВЎsicos de la rehabilitaciв”ңв”Ӯn, dejando que el libre mercado se encargara de la mejora de los aspectos sociales y econв”ңв”Ӯmicos. Asв”ңВЎ fue. En la imagen, la alcaldesa Luisa Fernanda Rudi y el concejal Josв”ңВ® Luis Santacruz, de inspecciв”ңв”Ӯn por la calle de San Blas a la altura del inmueble del nв”¬в•‘ 73, en el barrio de San Pablo.', 1998, 1998, 1998, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65665100, -0.88774500, '0101000020E61000002A00C6336868ECBF5EF1D4230DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24505520322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24505520322.webp', 'https://www.flickr.com/photos/zaragozaantigua/24505520322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25838, 'San Pablo 1844', '"Iglesia de San Pablo en Zaragoza". Dibujo de Genaro Pв”ңВ®rez de Villaamil incluido en la obra "Espaв”ңв–’a artв”ңВЎstica y monumental. Vistas y descripciв”ңв”Ӯn de los sitios y monumentos mв”ңГӯs notables de Espaв”ңв–’a". Fuente visual: www.flickr.com/photos/odisea2008/6309861440/', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24938529049.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24938529049.webp', 'https://www.flickr.com/photos/zaragozaantigua/24938529049/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25839, 'Calle Echeandв”ңВЎa 2005', 'Foto: Marina Ovejero. Solar vallado en la confluencia de la calle de Basilio Boggiero (desde donde estв”ңГӯ tomada la foto) con la de Pedro Echeandв”ңВЎa (al fondo), en septiembre de 2005. Durante 2006, esta zona, que incluye una plazuela en Boggiero frente al Oasis Club, fue objeto de algunos retoques estв”ңВ®ticos, culminados en 2010 con la urbanizaciв”ңв”Ӯn de parte del entorno, bautizв”ңГӯndola como plaza del Padre Pedro Dв”ңВЎez, que no merman su condiciв”ңв”Ӯn de lugar inhв”ңв”Ӯspito y ruinoso. A la derecha, inicio de las obras de construcciв”ңв”Ӯn de un bloque de viviendas esquinero entre Echeandв”ңВЎa y Boggiero. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65518700, -0.88522700, '0101000020E61000007C28D192C753ECBFD6E1E82ADDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30901813414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30901813414.webp', 'https://www.flickr.com/photos/zaragozaantigua/30901813414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25840, 'Calle de San Blas 1951', 'Imagen de la calle de San Blas capturada desde la replaceta que se formaba en el arranque de la calle del Sacramento (hacia la izquierda, fuera de plano), porque los nuevos edificios de los nв”ңв•‘meros 36-38, y 34-32, de la calle de San Blas habв”ңВЎan sido construidos retranqueados respecto de la anchura original de la calle, que era la que se ve que continв”ңв•‘a luego, primero hasta la antigua calle de la Golondrina (redenominada recientemente de mosв”ңВ®n Pedro Dosset), y luego hasta el desemboque en la plaza de Lanuza, donde el Mercado Central, al fondo. Mв”ңГӯs adelante, todos estos edificios referidos, desde el nв”ңв•‘mero 30, hasta el comienzo de la calle, serв”ңГӯn derribados y realineados los nuevos a la anchura moderna. A la derecha, y en primerв”ңВЎsimo plano, el muro junto a la puerta de San Blas de la iglesia parroquial de San Pablo. Fuente visual: Archivo Mora, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65629000, -0.88547100, '0101000020E610000029CE5147C755ECBF8E588B4F01D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30948308201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30948308201.webp', 'https://www.flickr.com/photos/zaragozaantigua/30948308201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25841, 'Calle San Blas 2006', 'Fotograma de la pelв”ңВЎcula documental "Gente con Gancho" (в”ңГјurea Martв”ңВЎnez, 2006), que retrata el barrio de San Pablo de Zaragoza. En la imagen, solar del nв”ңв•‘mero 61 de la calle de San Blas, esquinero con la de Mariano Cerezo (al fondo a la izquierda). En 2007 se levantarв”ңГӯ allв”ңВЎ el edificio Rв”ңВЎo Bidasoa. Fuente: www.permanencias.eu/. Un extracto del documental se puede ver en vimeo.com/35249591.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65659800, -0.88711500, '0101000020E6100000335019FF3E63ECBF3C4F3C670BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31411211084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31411211084.webp', 'https://www.flickr.com/photos/zaragozaantigua/31411211084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25843, 'Calle de Mayoral 2005', 'Foto: Josв”ңВ® Marв”ңВЎa Ballestв”ңВЎn Miguel. Imagen de la calle de Mayoral, centrada en el desaparecido tramo de los antiguos edificios nв”¬в•‘ 22 (derecha), 24 (centro), y 26 (izquierda), entre las calles de Boggiero y San Pablo. Conformaban una muestra de esa extraв”ңв–’a categorв”ңВЎa edilicia que los expertos suelen denominar "arquitectura popular", aunque sin los atributos estв”ңВ®ticos suficientes , y que suele traducirse como "contingente, prescindible", a efectos prв”ңГӯcticos, como es el caso. Luego fueron derribados, y en su lugar hay un solar de esos que no lo son.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65621000, -0.88903300, '0101000020E610000094128255F572ECBF72A774B0FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31835738354.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31835738354.webp', 'https://www.flickr.com/photos/zaragozaantigua/31835738354/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25845, 'Echeandв”ңВЎa 1951', 'Imagen de la calle de Gregorio Echeandв”ңВЎa capturada desde el recoleto espacio, o callejв”ңв”Ӯn, conformado entre los nв”ңв•‘meros 14 (izquierda) y 18 (derecha) de esa calle, como в”ңв•‘nica forma de acceder al nв”¬в•‘ 16. El mв”ңВЎnimo tamaв”ңв–’o de este callejв”ңв”Ӯn explicarв”ңВЎa que no tuviera denominaciв”ңв”Ӯn propia. La numeraciв”ңв”Ӯn de la calle Echeandв”ңВЎa avanza hacia la derecha, para desembocar en la calle de San Pablo. Hacia la izquierda, se llega a Boggiero. Fuente visual: foto Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65526400, -0.88483800, '0101000020E6100000EE4108C89750ECBF821FD5B0DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33233850661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33233850661.webp', 'https://www.flickr.com/photos/zaragozaantigua/33233850661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25846, 'Calle Boggiero 1890', 'Imagen de un interesante mirador abierto en el antiguo nв”¬в•‘ 35 de la calle Boggiero, en el tramo entre la calle de Mariano Cerezo y la de Miguel de Ara. Tiempo despuв”ңВ®s, la casona fue reconfigurada segв”ңв•‘n criterios estв”ңВ®ticos menos mestizos y mв”ңГӯs regionalistas, y este bizarro ajimez fue hecho desaparecer. Fuente visual: fototipia de Joarizti y Mariezcurrena, en Г”ГҮВЈZaragoza Artв”ңВЎstica, Monumental e Histв”ңв”ӮricaГ”ГҮГҳ, Anselmo y Pedro Gascв”ңв”Ӯn de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65530400, -0.88637200, '0101000020E610000033E202D0285DECBF10786000E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33784782044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33784782044.webp', 'https://www.flickr.com/photos/zaragozaantigua/33784782044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25848, 'Calle de Echeandв”ңВЎa c.1995', 'Imagen capturada en el tramo final de la serpenteante y recoleta calle de Pedro Gregorio Echeandв”ңВЎa y centrada en la fachada del antiguo nв”¬в•‘ 20 de esa calle, abandonado hacв”ңВЎa tiempo. Al poco serв”ңВЎa derribado, conservando la pared exterior hasta la altura de la planta calle. Asв”ңВЎ permaneciв”ңв”Ӯ hasta que en 2017 se iniciв”ңв”Ӯ la construcciв”ңв”Ӯn de un edificio residencial de cuatro plantas para 55 viviendas y 67 plazas de garaje, ademв”ңГӯs de varios locales comerciales, en los casi 1500 metros cuadrados de la manzana delimitada entre la avenida de Cв”ңВ®sar Augusto y las calles de San Pablo y Echeandв”ңВЎa. A la derecha, medianera con el nв”¬в•‘ 18 de la calle, que perdura. Fuente visual: AMZ.', 1995, 1995, 1995, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65539300, -0.88478400, '0101000020E610000022C500892650ECBF7F83F6EAE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40609576275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40609576275.webp', 'https://www.flickr.com/photos/zaragozaantigua/40609576275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25853, 'Calle de Basilio Boggiero 1993', 'Imagen capturada en la calle de Basilio Boggiero a la altura del inmueble del nв”¬в•‘ 28 ocupado por el Salв”ңв”Ӯn Oasis, activo como referente de la farв”ңГӯndula zaragozana desde su inauguraciв”ңв”Ӯn en 1909 como Royal Concert. En su fachada destaca el gran mural que en 1980 pintaran Sergio Abraв”ңВЎn Gracia y Miguel в”ңГјngel Encuentra Villamana. Ya desde los aв”ңв–’os 80 el cambio en las costumbres del ocio urbano y la acelerada degradaciв”ңв”Ӯn social y urbanв”ңВЎstica del entorno hicieron que la decadencia de este establecimiento culminara en diciembre de 1994 con su cierre, quedando como discoteca de fin de semana. Al fondo, solares que flanquean el arranque de la calle de Pedro Echeandв”ңВЎa. Por la derecha emerge una de las torrecillas de la iglesia de Santo Tomв”ңГӯs de Aquino o de los Escolapios.', 1993, 1993, 1993, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65518200, -0.88581500, '0101000020E6100000B8CCE9B29858ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50436273228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50436273228.webp', 'https://www.flickr.com/photos/zaragozaantigua/50436273228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25854, 'Calle del Conde de Aranda 1996', 'Imagen del aspecto de la calle del Conde Aranda (antigua del Portillo) desde su comienzo desde el cruce con la avenida de Cв”ңВ®sar Augusto, al fondo, donde se destaca el colegio de los Escolapios y la fachada de la Audiencia Terrirorial, en el arranque del tramo alto del Coso. La escena ha sido capturada a la altura del cruce con la calle de Mariano Cerezo (antigua de los Aguadores), donde el paso de peatones de primer tв”ңВ®rmino.', 1996, 1996, 1996, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65505400, -0.88775700, '0101000020E61000003B71395E8168ECBF978E39CFD8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50437087796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50437087796.webp', 'https://www.flickr.com/photos/zaragozaantigua/50437087796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25857, 'Plaza de San Pablo 1878', 'Imagen capturada desde cierta altura en la plaza de San Pablo por el fotв”ңв”Ӯgrafo villanovense Gregorio Sabatв”ңВ® Fв”ңВ®rriz e integrada en el в”ңГӯlbum "Vistas de Zaragoza", centrada en la iglesia parroquial de San Pablo Apв”ңв”Ӯstol. La imponente fachada luce la pв”ңВ®trea mв”ңГӯscara que le fue adosada al muro original durante una reforma de finales del siglo XVIII, flanqueando el ingreso de la puerta de San Pablo de finales del siglo XVI. Justo encima de ella, sobre la cornisa, icono de San Pablo aв”ңв–’adido en 1858 y tallado por Antonio Palao. A la izquierda y hacia el fondo despuntan las cupulillas de las capillas de Santiago, San Miguel y de Nв”¬В¬. Sв”¬В¬. del Pв”ңв”Ӯpulo. A la derecha, cв”ңв•‘pula de la capilla de San Pedro y San Pablo. Del conjunto emerge la impresionante atalaya del templo, posiblemente la primera torre de planta octogonal construida en ladrillo y yeso en todo el occidente europeo durante la taifa de Saraqusta (siglo XI), luego reconvertida en torre tras la conquista cristiana con varios recrecimientos en los siglos XIII, XVI y XVII, y culminada en 1859 con el chapitel y veleta que luce en la imagen, proyectado por Josв”ңВ® de Yarza Echenique.', 1878, 1878, 1878, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65600800, -0.88620100, '0101000020E610000002D71533C25BECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54764908200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54764908200.webp', 'https://www.flickr.com/photos/zaragozaantigua/54764908200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25875, 'Palacio de la Condesa de Bureta 1848', 'L''Espagne pittoresque, artistique et monumentale. Manuel de Cuendв”ңВЎas y V. de Fв”ңВ®rв”ңВ®al. Paris, 1848. Dibujo que toma como modelo otro de 1837 (www.flickr.com/photos/zaragozaantigua/20709111276) en el que se ve en primer plano a la derecha la casa-palacio de la Condesa de Bureta, Marв”ңВЎa de la Consolaciв”ңв”Ӯn Domitila Azlor y Villavicencio (1773-1814), considerada heroв”ңВЎna de los Sitios de Zaragoza (1808-1809). La direcciв”ңв”Ӯn actual del solar es Torre Nueva 2, Zaragoza: lugar que ocuparon los almacenes SEPU (Sociedad Espaв”ңв–’ola de Precio в”ңГңnico) y hoy edificio de viviendas. Al fondo, la Torre Nueva, en la plaza de San Felipe, mucho mв”ңГӯs inclinada de lo que estaba, para mayor espectacularidad de la estampa. Fuente: www.facebook.com/photo.php?fbid=1569173149969072&set=...', 1848, 1848, 1848, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15451579300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15451579300.webp', 'https://www.flickr.com/photos/zaragozaantigua/15451579300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23753, 'Castillo de Alfocea 2006', 'Imagen de los restos del castillo de Alfocea, en este barrio rural de Zaragoza. A la izquierda se observa la tapia que rodea al cementerio que ocupa su solar. El nombre deriva de Al-Hauz (finca de descanso), que es como se conocв”ңВЎa el lugar en el momento de elevarse la fortaleza musulmana, que forma parte del conjunto que rodeaba la ciudad de Saraqusta. Fue ocupado por el ejв”ңВ®rcito cristiano que tomв”ңв”Ӯ Zaragoza en 1118. Reconvertido en ermita de Santa Ana, en el siglo XIX ya se dedicв”ңв”Ӯ a cementerio. Fuente: www.zaragoza.es', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.72363300, -0.95008300, '0101000020E6100000C689AF761467EEBF37A79201A0DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19246174294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19246174294.webp', 'https://www.flickr.com/photos/zaragozaantigua/19246174294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25878, 'Alteraciones 1843', 'Grabado acerca de las revueltas en Zaragoza, 1843. En la Zaragoza de 1843 se produjeron dos pronunciamientos militares, en junio y en septiembre. El que ilustra el dibujo fue el primero, durante la regencia del General Espartero. Fue sofocado por la oposiciв”ңв”Ӯn de la tropa, el pueblo y las autoridades locales. En la imagen, en primer plano a la derecha la casa-palacio de la Condesa de Bureta, Marв”ңВЎa de la Consolaciв”ңв”Ӯn Domitila Azlor y Villavicencio (1773-1814), considerada heroв”ңВЎna de los Sitios de Zaragoza (1808-1809). La direcciв”ңв”Ӯn actual del solar es Torre Nueva 2, Zaragoza: lugar que ocuparon los almacenes SEPU (Sociedad Espaв”ңв–’ola de Precio в”ңГңnico) y hoy edificio de viviendas. Al fondo, la Torre Nueva, en la plaza de San Felipe, mucho mв”ңГӯs inclinada de lo que estaba, para mayor espectacularidad de la estampa. Fuente: Illustrated London News, 19 de agosto de 1843.', 1843, 1843, 1843, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19836053439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19836053439.webp', 'https://www.flickr.com/photos/zaragozaantigua/19836053439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25879, 'Torre Nueva 1837', '"Leaning Tower of Saragossa", dibujo de David Roberts (1796/1864). Viajв”ңв”Ӯ por Espaв”ңв–’a en 1832 y 1833. Grabado por Henry Adlard publicado en Londres en 1837 por Robert Jennings & Co. En el grabado podemos ver la Torre Nueva con una exagerada inclinaciв”ңв”Ӯn, desde la perspectiva de la calle Torre Nueva, con el palacio de la Condesa de Bureta (primer edificio de la derecha). Fuente: www.facebook.com/photo.php?fbid=10206852722334632&set...', 1837, 1837, 1837, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20709111276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20709111276.webp', 'https://www.flickr.com/photos/zaragozaantigua/20709111276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25885, 'Torre Nueva 1837', 'Litografв”ңВЎa de Jules Huyot realizada hacia 1865 y titulada "Tour inclinв”ңВ®e в”ңГЎ Saragosse", una nueva versiв”ңв”Ӯn del clв”ңГӯsico grabado "Leaning Tower of Saragossa" de David Roberts. Respecto del original cambian los figurinistas y el atrezo urbano, y perdura la llamativa inclinaciв”ңв”Ӯn de la Torre Nueva capturada desde la homв”ңв”Ӯnima calle, destacando a la derecha la antigua casa de los condes de Bureta. Fuente visual: www.cortesaragon.es/', 1837, 1837, 1837, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26166286408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26166286408.webp', 'https://www.flickr.com/photos/zaragozaantigua/26166286408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25931, 'Calle de Cerdв”ңГӯn 1952', 'Imagen capturada en la calle de Juan Jimв”ңВ®nez Cerdв”ңГӯn, antigua de la Albarderв”ңВЎa, centrada en la tranviaria unidad nв”¬в•‘ 152 de la lв”ңВЎnea 7 &quot;Ayuntamiento-Portillo&quot; dirigiв”ңВ®ndose a la terminal de la plaza de Espaв”ңв–’a. Esta unidad estuvo en servicio hasta la clausura de la lв”ңВЎnea en 1959, pasando luego a la lв”ңВЎnea 1 &quot;Bajo Aragв”ңв”Ӯn&quot;. Fue desguazada en 1970. De fondo edilicio, la calle de Cerdв”ңГӯn a la altura de la calle de Felipe Perena (a la derecha, fuera de plano), posiblemente en el tramo de los nв”ңв•‘meros 17 a 27, con sus referenciales bajos comerciales. Es curioso que, sin trв”ңГӯfico rodado ni aparcamiento en superficie, muchas de las tradicionales calles de la ciudad parecen ensancharse de forma mв”ңГӯgica, de forma que incluso la presencia del tranvв”ңВЎa tiene su espacio. Y el comercio de proximidad, las tiendas de toda la vida, sin afecciones o menoscabo de su actividad. Fuente visual: Josв”ңВ® Marв”ңВЎa Valero Suв”ңГӯrez, Centenario del tranvв”ңВЎa elв”ңВ®ctrico. Zaragoza, 1902-2002.', 1952, 1952, 1952, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65477500, -0.88411900, '0101000020E61000000FB6D8EDB34AECBF849ECDAACFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41315982345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41315982345.webp', 'https://www.flickr.com/photos/zaragozaantigua/41315982345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25969, 'Vista aв”ңВ®rea 1925', 'Vista por encima del hombro de la ciudad, focalizando el entorno del decumano maximo romano, desde la calle Manifestaciв”ңв”Ӯn, pasando por Espoz y Mina, hasta la calle Mayor. La imagen capta el estado de la zona antes del Plan de Reforma Interior de 1939. Apenas visible, al fondo, la zona donde serв”ңГӯ abierta la calle S. Vicente de Paв”ңв•‘l, actuando sobre 30.000 m2, derribando 154 construcciones de los siglos XVI-XVII (entre ellas, la casa-palacio de Sora, y La Enseв”ңв–’anza). Mucho mв”ңГӯs visible, en el centro, las plazas de la Seo, el Pilar, y s. Juan de los Panetes, reformadas mediante la intervenciв”ңв”Ӯn sobre 58.000 m2, y la demoliciв”ңв”Ӯn de 224 inmuebles de los siglos XVI a XVIII, entre ellos, el convento de las Angв”ңВ®licas, la casa de los Infantes del Pilar, el convento y colegio de las Mercedarias, las oficinas de la delegaciв”ңв”Ӯn de Hacienda en un palacio del XVI, la iglesia de los Agustinos, o la capilla del Carmen. En este caso, el nuevo espacio resultante tendrв”ңВЎa 50 m. de ancho, y 500 m. de largo, y estarв”ңВЎa delimitado por el Pilar, la Lonja, el Palacio Arzobispal, la Seo, y 7 nuevas manzanas en las que se levantarв”ңВЎan la Casa Consistorial, el Gobierno Civil, los Juzgados, la Hospederв”ңВЎa del Pilar, y el Colegio de Infantes, entre otras. Otras construcciones, como la iglesia de S. Juan y S. Pedro, no tuvieron que esperar a un plan de reforma en concreto para ser extinguidas, allв”ңГӯ por los felices aв”ңв–’os 60 del pasado siglo. No se ha demostrado que en nada de esto tuvieran algo que ver los franceses. Fuente visual: J. Ortв”ңВЎz Echagв”ңв•қe, "Espaв”ңв–’a. Pueblos y Paisajes".', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65499000, -0.88502100, '0101000020E61000002FBE688F1752ECBF809A5AB6D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14852987862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14852987862.webp', 'https://www.flickr.com/photos/zaragozaantigua/14852987862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25986, 'Vista San Pablo c.1985', 'Foto colecciв”ңв”Ӯn particular Celia Sв”ңГӯnchez, hacia 1985. Vista del barrio de San Pablo desde el edificio de la calle del Conde de Aranda 94-96. En primer plano, la torre de la iglesia de San Pablo y su caserв”ңВЎo circundante. Al fondo, el Pilar, la iglesia de Santa Isabel y la Seo. Fuente: www.facebook.com/photo.php?fbid=1493185717610553&set=...', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65536500, -0.88603400, '0101000020E61000002C9CA4F9635AECBFB6F81400E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15525164919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15525164919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15525164919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23756, 'Iglesia de Alfocea 1995', 'Foto Gonzalo Bullв”ңв”Ӯn, 1995. Iglesia de la Inmaculada de Alfocea, edificio barroco de 1683. Fuente: Zaragoza. Guв”ңВЎa de arquitectura. CAI, 2005.', 1995, 1995, 1995, 'Anos 90', NULL, 41.72414600, -0.95113400, '0101000020E610000023A30392B06FEEBFBDC3EDD0B0DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20118210355.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20118210355.webp', 'https://www.flickr.com/photos/zaragozaantigua/20118210355/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20930, 'Casa de Argillo 1564', '"Fachada de la casa de los Condes de Argillo de Zaragoza". Dibujo de Valentв”ңВЎn Carderera y Solano, realizado en 1855, con una vista parcial de la fachada del original y renacentista palacio que los Condes de Argillo poseв”ңВЎan en la calle Mayor, cerca de la iglesia parroquial de Nв”¬В¬ Sв”¬В¬ de Marв”ңВЎa Magdalena, tal vez esquinero con la calle de las Cuatro Esquinas. Como el autor anotв”ңв”Ӯ posteriormente, en la parte inferior izquierda del dibujo, esta casa fue "Demolida" aв”ңв–’os despuв”ңВ®s de capturarla con el lв”ңГӯpiz. El primer conde de Argillo se habв”ңВЎa instalado en este caserв”ңв”Ӯn a finales del siglo XVIII, y uno de sus descendientes heredв”ңв”Ӯ luego el tв”ңВЎtulo y propiedades del marquв”ңВ®s de Villaverde, entre ellas, el palacio sito en la plaza de San Felipe, que comenzв”ңв”Ӯ a ser denominado tambiв”ңВ®n, por ello, palacio de Argillo. El derribo del edificio de la calle Mayor, sobre 1860, ayudв”ңв”Ӯ a simplificar las cosas, y el equв”ңВЎvoco en las denominaciones. En la imagen, la fachada ha sido ambientada con una evocadora figura femenina de los tiempos de Felipe II. Fuente visual: ceres.mcu.es/', 1564, 1564, 1564, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65269900, -0.87488100, '0101000020E61000006E895C7006FFEBBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24886570752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24886570752.webp', 'https://www.flickr.com/photos/zaragozaantigua/24886570752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21441, 'Vista desde la Magdalena c.1910', 'Imagen del caserв”ңВЎo urbano capturada desde la altura de la aparentemente barroca torre de la iglesia parroquial de Santa Marв”ңВЎa Magdalena, orientada hacia el occidente siguiendo la traza del antiguo "decumano maximo", identificado con la estrecha cinta oscura de la calle Mayor, a la izquierda. En primer tв”ңВ®rmino, tejados recayentes a la perpendicular calle de Tomв”ңГӯs Fermв”ңВЎn Lezaun, que comunica con la paralela calle de Don Juan de Aragв”ңв”Ӯn, en cuyo nв”¬в•‘ 15 estuvo ubicada la primera escuela municipal de niв”ңв–’as, luego sede de la Escuela Normal de Maestras; y en el nв”¬в•‘ 11-13, la luminosa y gran estructura del colegio de la Compaв”ңв–’в”ңВЎa de las Hijas de la Caridad de San Vicente de Paв”ңв•‘l, notablemente ampliado en 1909 para albergar el Asilo de la Coronaciв”ңв”Ӯn para niв”ңв–’os precarios. Hacia el fondo y a la derecha, techumbre, cimborrio y torre de la Seo; el templo del Pilar con sus dos torres recayentes a la homв”ңв”Ӯnima plaza. Mв”ңГӯs al fondo, meandro de Ranillas y el rв”ңВЎo Ebro curveando su cauce.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65331800, -0.87476400, '0101000020E610000009FB761211FEEBBFAEF199EC9FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48885788507.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48885788507.webp', 'https://www.flickr.com/photos/zaragozaantigua/48885788507/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21787, 'Proyecto calle de la Yedra 1937', 'Proyecto de ampliaciв”ңв”Ӯn de la zona afectada por la apertura de la calle de la Yedra. Nuevas expropiaciones. Regino Borobio, Zaragoza, enero de 1937. Aunque el proyecto de arrasar esa zona de la ciudad, desde el Coso Medio a la altura de la calle de la Yedra hasta el paseo del Ebro data de 1869, con nuevos intentos en 1887 y 1905, las obras de demoliciв”ңв”Ӯn de edificios comenzaron en 1936. Aunque la destrucciв”ңв”Ӯn mв”ңГӯs significativa se dio en la dв”ңВ®cada de los 40, la calle de San Vicente de Paв”ңв•‘l se terminв”ңв”Ӯ en 15 aв”ңв–’os, en junio de 1951. Mide 550 metros de largo y 15 de ancho. Fuente visual: Zaragoza, espacio histв”ңв”Ӯrico. Ayuntamiento de Zaragoza, 2006.', 1937, 1937, 1937, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65285500, -0.87547400, '0101000020E61000001BF2CF0CE203ECBFDA03ADC090D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23823914519.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23823914519.webp', 'https://www.flickr.com/photos/zaragozaantigua/23823914519/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21867, 'Calle de Argensola 1934', 'Imagen capturada en el arranque de la calle de Argensola desde la plaza de San Pedro Nolasco, con detalle de los diversos comercios ubicados en los primeros nв”ңв•‘meros pares. En el antiguo nв”ңв•‘mero 6, con la fachada revocada, la antigua casa de los Albiв”ңв”Ӯn, luego de los Argensola, y en la que naciera Fernando Garcв”ңВЎa Mercadal en 1896. Hacia la izquierda, fuera de plano, la calle de San Juan, conducente a la iglesia parroquial de San Juan y San Pedro. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65313200, -0.87675900, '0101000020E61000004128EFE3680EECBF4CFC51D499D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36422199616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36422199616.webp', 'https://www.flickr.com/photos/zaragozaantigua/36422199616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21951, 'Calle de Don Juan de Aragв”ңв”Ӯn 1949', 'Imagen parcial del traumatismo ocasionado por el bisturв”ңВЎ urbanв”ңВЎstico que abriв”ңв”Ӯ la nueva calle para coches de San Vicente de Paв”ңв•‘l durante la dв”ңВ®cada de los cuarenta del pasado siglo XX. En este caso, la calle de Don Juan de Aragв”ңв”Ӯn ha sido seccionada para conectar lo que durante siglos estuvo separado: la antigua plaza del Reino (a la derecha, desaparecida) y la calle de Lezaв”ңв•‘n, antes del Fierro (a la izquierda, desaparecida). Todo el caserв”ңВЎo de la zona fue derribado para amoldarse a la nueva traza, excepto el palacio de los Lazв”ңГӯn (a la derecha), que tuvo la fortuna de coincidir justo con la ortogonal y nueva arteria vial. Al resto le sucediв”ңв”Ӯ lo que a los edificios de la imagen: derribo, vallado, y construcciв”ңв”Ӯn de nuevos edificios amoldados a la calle. En ese solar se estв”ңГӯ comenzando a levantar el nuevo colegio de la Compaв”ңв–’в”ңВЎa de las Hijas de la Caridad de San Vicente de Paв”ңв•‘l, cuya esquina chaflaneada caracteriza hoy la zona. Al fondo, se elevan la torre nueva del Pilar, y la veterana de la Seo. Entre ambas, las traseras de los edificios de las calles Lucero y Deв”ңГӯn. Fuente visual: Archivo Mora, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65348300, -0.87490400, '0101000020E6100000797764AC36FFEBBFF9BEB854A5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18740664341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18740664341.webp', 'https://www.flickr.com/photos/zaragozaantigua/18740664341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21956, 'Calle Mayor c.1943', 'Dibujo de Ambrosio Ruste de la calle Mayor, antes de ser cortada por el ensanche y prolongaciв”ңв”Ӯn de la calle de la Yedra. A la izquierda, entre las calles Cedro y Lezaв”ңв•‘n, la fachada de la casa del conde de Torreflorida, en los nв”ңв•‘mero 43 y 45, derribada en 1942. Al fondo, la torre de la iglesia de la Magdalena, con su chapitel barroco. Fuente: в”¬ГӯAquв”ңВЎ... Zaragoza!, Josв”ңВ® Blasco Ijazo, 1950.', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65300200, -0.87510800, '0101000020E610000098F90E7EE200ECBF7E1CCD9195D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20003915511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20003915511.webp', 'https://www.flickr.com/photos/zaragozaantigua/20003915511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26077, 'Parque Primo de Rivera 1963', 'Imagen capturada sobrevolando el antiguo parque de Buenavista (entonces denominado parque de Primo de Rivera) con una vista centrada en parte del recorrido establecido con motivo de la disputa del XII Gran Premio Internacional motorista "Nв”¬В¬. Sв”¬В¬. del Pilar" organizado por el Motor Club de Aragв”ңв”Ӯn en el marco de las fiestas mayores de la ciudad en el mes de octubre de ese aв”ңв–’o. Numeroso pв”ңв•‘blico flanquea el alabeado tramo entre la avenida de San Sebastiв”ңГӯn y la avenida de los Bearneses. En primer tв”ңВ®rmino, huertos municipales donde aв”ңв–’os despuв”ңВ®s se ubicarв”ңВЎa el nuevo Jardв”ңВЎn Botв”ңГӯnico de la ciudad. Hacia el fondo y tras el paseo de Mariano Renovales, feraz zona agrв”ңВЎcola delimitada entre al antiguo camino del Sв”ңГӯbado (tramo luego redenominado calle del Arzobispo Morcillo), donde destaca el Grupo Residencial Salduba, y el antiguo camino viejo de Cuarte (actual calle de Julio Cejador Frauca), donde a la derecha destaca una vista parcial de la harinera "La Imperial de Aragв”ңв”Ӯn".', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.63415200, -0.89400100, '0101000020E6100000E6EB32FCA79BECBFB4588AE42BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53271470291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53271470291.webp', 'https://www.flickr.com/photos/zaragozaantigua/53271470291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22407, 'Calle Mayor 1968', 'Imagen en 1968 de la calle Mayor donde arranca, inmediata y hacia la izquierda, la calle Cedro, y donde desemboca, desde la derecha, la calle de los hermanos Argensola. Este tramo de la calle estaba siendo realineado, de forma que un buen nв”ңв•‘mero de antiguos inmuebles de la acera de los pares estaban siendo sustituidos por otros mв”ңГӯs modernos. En el momento de capturar esta imagen, por ejemplo, en la esquina con Argensola, el solar de los antiguos 28-30 (luego 18), ya derribado, ejercв”ңВЎa transitoria y graciosamente como estacionamiento "duty free". La casona del antiguo 32, con la visual despejada, recuerda la monumental tipologв”ңВЎa de edificios que una vez caracterizara esta notable calle. A este edificio tambiв”ңВ®n le llegarв”ңВЎa su San Martв”ңВЎn, y serв”ңВЎa sustituido por otra cosa. Al fondo, despunta la torre de la iglesia parroquial de Santa Marв”ңВЎa Magdalena, reciв”ңВ®n despojada de sus barrocos atavв”ңВЎos. A la izquierda, cartel del filme "La mujer indomable" (The Taming of the Shrew), con el dв”ңв•‘o Taylor & Burton, proyectada en el "Pax", ademв”ңГӯs de un buen muestrario de rв”ңв”Ӯtulos y carteles de establecimientos de la zona. La impactante y notable sensaciв”ңв”Ӯn de caв”ңВЎda libre, conforme la calle se aproxima a la iglesia parroquial, al fondo, tiene su explicaciв”ңв”Ӯn altimв”ңВ®trica en los dos metros de desnivel que hay entre ambos puntos. Fuente: "Zaragoza Viva" (1969).', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65355700, -0.87644800, '0101000020E6100000A1A014ADDC0BECBF33897AC1A7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24480982941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24480982941.webp', 'https://www.flickr.com/photos/zaragozaantigua/24480982941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23446, 'Calle Mayor aв”ңв–’os 20', 'Otto Wв”ңв•қnderlich. 1920-1936. "Zaragoza. Calle Mayor [La Torre de la Seo o Catedral del Salvador en su Epifanв”ңВЎa, al fondo]". Imagen capturada desde el cruce de la calle Mayor con la de Argensola. A la izquierda, entre la calle del Cedro y la de Lezaв”ңв•‘n, la imponente fachada de la casa palacio del conde de Torreflorida, en el nв”ңв•‘mero 43-45, derribada en 1942. Al fondo, la silueta de la torre de la iglesia de la Magdalena (no de La Seo). Fuente visual: Archivo Wв”ңв•қnderlich ( WUN-05814) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65300200, -0.87510800, '0101000020E610000098F90E7EE200ECBF7E1CCD9195D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060746781.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060746781.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060746781/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23452, 'Calle Mayor c.1935', 'AHPZ. Juan Mora Insa. "Zaragoza, calle Mayor. Alero, [del palacio] Conde de Torreflorida. Estilo: Renacimiento." En la extensa nв”ңв”Ӯmina de construcciones de los siglos XVI-XVII de la ciudad que no han llegado a ver el siglo XXI, se encuentra la Casa o Palacio del Conde de Torreflorida, localizado en el nв”¬в–‘ 43-45 de la calle Mayor, en el tramo entre la del Cedro y la de Lezaв”ңв•‘n. En enero de 1936, la publicaciв”ңв”Ӯn del SIPA "Aragв”ңв”Ӯn" todavв”ңВЎa glosaba la magnificiencia de sus "miradores", o galerв”ңВЎa de arquillos del alero volado de madera, en estilo gв”ңв”Ӯtico-mudв”ңВ®jar. El Palacio serв”ңВЎa piqueteado en 1942. En la imagen, el lado largo del alero daba a la calle Mayor.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65292900, -0.87492500, '0101000020E6100000567DAEB662FFEBBF14CE6E2D93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15159220638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15159220638.webp', 'https://www.flickr.com/photos/zaragozaantigua/15159220638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23458, 'Palacio de Torreflorida 1942', 'Portada plateresca en el Palacio de Torreflorida. 1942. La casa palacio de Torreflorida, en el nв”ңв•‘mero 43-45 de la calle Mayor, tenв”ңВЎa una interesante portada plateresca y un patio de dos cuerpos, ademв”ңГӯs de amplios salones y jardines donde brillaba una fuente renacentista de varios surtidores. Todo esto fue piqueteado, junto con sus "miradores", o galerв”ңВЎa de arquillos del alero volado de madera, en estilo gв”ңв”Ӯtico-mudв”ңВ®jar. Corrв”ңВЎa el aв”ңв–’o de 1942. Fuente: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65292900, -0.87492500, '0101000020E6100000567DAEB662FFEBBF14CE6E2D93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16189847619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16189847619.webp', 'https://www.flickr.com/photos/zaragozaantigua/16189847619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23564, 'Calle San Lorenzo c.1965', 'Dibujo recreando la antigua casona esquinera en la confluencia de la calle del Salvaje (desde la izquierda) en la de San Lorenzo, parroquia de la Magdalena. Se trataba de una construcciв”ңв”Ӯn en el estilo popular que desde los siglos XVI-XVII caracterizaba muchos de los edificios habitacionales de la ciudad, con posteriores reformas en el XVIII y XIX. Ocupaba los antiguos 42 y 44 accesorio de la calle San Lorenzo, y el 11 de la calle de los Estudios (redenominaciв”ңв”Ӯn de la del Salvaje), y estuvo en pie hasta que a finales de los aв”ңв–’os 60 la manzana San Lorenzo-Estudios-Espino fue actualizada en buena parte de sus construcciones. Desde 1970, en su lugar, se levanta el actual 15-17 de la calle de los Estudios. A su derecha, perdura el actual nв”¬в•‘ 30 de la calle San Lorenzo, edificio de la misma в”ңВ®poca, que nos ofrece la posibilidad de imaginar cв”ңв”Ӯmo era el edificio de la imagen, denominado "Casa Caliba". Fuente visual: "Recordando Zaragoza: obra grв”ңГӯfica, ilustrada con viв”ңв–’etas entre textos, y diez dibujos de Rafael Margalв”ңВ®". Imagen amablemente proporcionada por Josв”ңВ® Luis Cintora.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65217000, -0.87455900, '0101000020E6100000D384ED2763FCEBBF56B77A4E7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23191076269.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23191076269.webp', 'https://www.flickr.com/photos/zaragozaantigua/23191076269/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23575, 'Calle San Lorenzo aв”ңв–’os 30', 'Acuarela de Ambrosio Ruste, con la calle de San Lorenzo y la de los Estudios a la izquierda. Fuente: Lв”ңГӯminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65214900, -0.87455200, '0101000020E610000034D8D47954FCEBBF3F8F519E79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32400482876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32400482876.webp', 'https://www.flickr.com/photos/zaragozaantigua/32400482876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24535, 'Calle de San Vicente de Paв”ңв•‘l 1951', 'Imagen capturada en la calle San Lorenzo y centrada en el reciв”ңВ®n inaugurado Mercado de San Vicente de Paв”ңв•‘l, proyectado por los arquitectos Josв”ңВ® de Yarza y Josв”ңВ® Beltrв”ңГӯn en la manzana ubicada entre la homв”ңв”Ӯnima calle que le da nombre, en primer tв”ңВ®rmino y las calles de San Lorenzo (derecha), Pedro Calixto Ramв”ңВЎrez (al fondo), y Mayor (izquierda). Construido en ladrillo y revestido de piedra de Calatorao en su cuerpo inferior y fachada principal, su versiв”ңв”Ӯn definitiva fue despojada de los remates con veletas sobre chapiteles o agujas que le daban un tono mв”ңГӯs tradicionalista y menos moderno. Los accesos a los bloques de viviendas laterales tambiв”ңВ®n fueron modificados, y dispuestos en los chaflanes laterales. Al fondo y a la derecha, vista parcial del antiguo inmueble del nв”¬в•‘ 2 de la calle de Pedro Calixto Ramв”ңВЎrez, derribado a finales de los prodigiosos aв”ңв–’os sesenta y sustituido por otro mв”ңГӯs moderno. A la derecha, vista parcial del inmueble del nв”¬в•‘ 28 de la calle de San Vicente de Paв”ңв•‘l, con su torreв”ңв”Ӯn chaflanero aв”ңв–’adido tras una reciente reforma.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65275300, -0.87535500, '0101000020E6100000897B2C7DE802ECBFD5AE09698DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50099567163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50099567163.webp', 'https://www.flickr.com/photos/zaragozaantigua/50099567163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
